mapper.select:
SELECT id, code, type, title, description, status, priority, provider_id, external_work_item_id, project_id, space_id, iteration_id, project_context_id, project_space_id, project_iteration_id, owner_user_id, assignee_user_id, current_workflow_instance_id, extra_json, version, created_at, updated_at FROM work_item
project_id = #{projectId}
AND space_id = #{spaceId}
AND iteration_id = #{iterationId}
ORDER BY updated_at DESC, created_at DESC

mapper.update:
UPDATE work_item
SET title = #{title}, description = #{description}, status = #{status},
    priority = #{priority}, assignee_user_id = #{assigneeUserId},
    current_workflow_instance_id = #{currentWorkflowInstanceId},
    version = #{version}, updated_at = #{updatedAt}
WHERE id = #{id}
